2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	export const KNOWN_ITEM_TYPES = new Set<string>(Object.keys(BASE_PREMIUM_BY_ITEM_TYPE));
16	
17	const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
20	const CURSED_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const LOYALTY_DISCOUNT_RATE = 0.2;
24	const LOYALTY_YEARS_THRESHOLD = 2;
25	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
26	
27	function loyaltyDiscountFor(yearsInsured: number, baseTotal: number): number {
28	  return yearsInsured >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
29	}
30	
31	function followUpDiscountFor(contractNumber: number, baseTotal: number): number {
32	  return contractNumber > 1 ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
33	}
34	
35	function withFirstInsurance(basePremium: number): number {
36	  return basePremium + basePremium * FIRST_INSURANCE_RATE;
37	}
38	
39	function premiumForTypeGroup(type: string, count: number): number {
40	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
41	    return withFirstInsurance(COMPONENT_BLOCK_BASE_PREMIUM);
42	  }
43	  return count * withFirstInsurance(BASE_PREMIUM_BY_ITEM_TYPE[type]);
44	}
45	
46	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
47	
48	function surchargeRateForItem(item: Item): number {
49	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
50	  const enchantmentRate =
51	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
52	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
53	      : 0;
54	  return cursedRate + enchantmentRate;
55	}
56	
57	function surchargeForItem(item: Item): number {
58	  return BASE_PREMIUM_BY_ITEM_TYPE[item.type] * surchargeRateForItem(item);
59	}
60	
61	const CLAIM_DEDUCTIBLE = 100;
62	const CAP_MULTIPLIER = 2;
63	const REDUCED_REIMBURSEMENT_RATE = 0.5;
64	const REDUCED_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
65	const MATERIALS_EXEMPT_FROM_REDUCED_REIMBURSEMENT = new Set<string>(["dragon"]);
66	
67	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
68	  sword: 1000,
69	  amulet: 600,
70	  staff: 800,
71	  potion: 400,
72	  rune: 250,
73	  moonstone: 250,
74	};
75	
76	type Damage = { type: string; amount: number };
77	
78	function insuranceCapFor(items: Item[]): number {
79	  const insuranceSum = items.reduce(
80	    (sum, item) => sum + INSURANCE_VALUE_BY_ITEM_TYPE[item.type],
81	    0,
82	  );
83	  return insuranceSum * CAP_MULTIPLIER;
84	}
85	
86	function isExemptFromReducedReimbursement(item: Item): boolean {
87	  return (
88	    COMPONENT_TYPES.has(item.type) ||
89	    MATERIALS_EXEMPT_FROM_REDUCED_REIMBURSEMENT.has(item.material ?? "")
90	  );
91	}
92	
93	function hasReducedReimbursement(item: Item): boolean {
94	  if (isExemptFromReducedReimbursement(item)) return false;
95	  return (item.enchantment ?? 0) >= REDUCED_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
96	}
97	
98	function reimbursementFor(damage: Damage, items: Item[]): number {
99	  const matchingItem = items.find((item) => item.type === damage.type);
100	  if (matchingItem && hasReducedReimbursement(matchingItem)) {
101	    return damage.amount * REDUCED_REIMBURSEMENT_RATE;
102	  }
103	  return damage.amount;
104	}
105	
106	function rawPayoutFor(damages: Damage[], items: Item[]): number {
107	  const reimbursementTotal = damages.reduce(
108	    (sum, d) => sum + reimbursementFor(d, items),
109	    0,
110	  );
111	  return reimbursementTotal - CLAIM_DEDUCTIBLE;
112	}
113	
114	function payoutAgainstCap(damages: Damage[], items: Item[], remainingCap: number): number {
115	  return Math.floor(Math.min(rawPayoutFor(damages, items), remainingCap));
116	}
117	
118	function handleClaim(scenario: any): { payout: number; remainingCap: number } {
119	  const damages: Damage[] = scenario.damages ?? [];
120	  const items: Item[] = scenario.items ?? [];
121	  const cap = insuranceCapFor(items);
122	  const payout = payoutAgainstCap(damages, items, cap);
123	  return { payout, remainingCap: cap - payout };
124	}
125	
126	function handleQuote(scenario: any): { premium: number } {
127	  const items: Item[] = scenario.items ?? [];
128	  const countsByType: Record<string, number> = {};
129	  let surchargesTotal = 0;
130	  let baseTotal = 0;
131	  for (const item of items) {
132	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
133	    surchargesTotal += surchargeForItem(item);
134	    baseTotal += BASE_PREMIUM_BY_ITEM_TYPE[item.type];
135	  }
136	  let itemsTotal = 0;
137	  for (const type of Object.keys(countsByType)) {
138	    itemsTotal += premiumForTypeGroup(type, countsByType[type]);
139	  }
140	  const yearsInsured = scenario.customer?.yearsInsured ?? 0;
141	  const contractNumber = scenario.customer?.contractNumber ?? 1;
142	  const loyaltyDiscount = loyaltyDiscountFor(yearsInsured, baseTotal);
143	  const followUpDiscount = followUpDiscountFor(contractNumber, baseTotal);
144	  return {
145	    premium: Math.ceil(itemsTotal + surchargesTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE),
146	  };
147	}
148	
149	function runSteps(scenario: any): unknown {
150	  const customer = scenario.customer;
151	  const policies: { items: Item[]; remainingCap: number }[] = [];
152	  const results: unknown[] = [];
153	  for (const step of scenario.steps) {
154	    if (step.op === "quote") {
155	      const items: Item[] = step.items ?? [];
156	      results.push(handleQuote({ customer, items }));
157	      policies.push({ items, remainingCap: insuranceCapFor(items) });
158	    } else if (step.op === "claim") {
159	      const policy = policies[step.policy];
160	      const damages: Damage[] = step.damages ?? [];
161	      const payout = payoutAgainstCap(damages, policy.items, policy.remainingCap);
162	      policy.remainingCap -= payout;
163	      results.push({ payout, remainingCap: policy.remainingCap });
164	    }
165	  }
166	  return { results };
167	}
168	
169	export function runScenario(scenario: any): unknown {
170	  if (scenario.steps) {
171	    return runSteps(scenario);
172	  }
173	  if (scenario.command === "claim") {
174	    return handleClaim(scenario);
175	  }
176	  return handleQuote(scenario);
177	}
